/* Graduation Invitation v3 - Static JS */
const CONFIG={graduationDate:"2026-08-02T10:00:00+07:00",storageKey:"pham-nhu-quynh-guestbook"};
const pageText=window.INVITATION_CONFIG?.pageText||{};document.querySelectorAll("[data-config-text]").forEach(el=>{const key=el.dataset.configText;if(pageText[key])el.textContent=pageText[key]});document.querySelectorAll("[data-config-html]").forEach(el=>{const key=el.dataset.configHtml;if(pageText[key])el.innerHTML=pageText[key]});
const topbar=document.querySelector(".topbar"),heroName=document.querySelector(".hero-name");function updateToolbarState(){if(!topbar)return;topbar.classList.toggle("toolbar-solid",window.scrollY>60);if(heroName){const barHeight=topbar.offsetHeight||44;const nameRect=heroName.getBoundingClientRect();topbar.classList.toggle("toolbar-title-visible",nameRect.top<=barHeight+8)}}window.addEventListener("scroll",updateToolbarState,{passive:true});window.addEventListener("resize",updateToolbarState);updateToolbarState();
const themeBtn=document.getElementById("themeBtn"),themeKey="graduation-theme";function setTheme(theme){document.documentElement.classList.toggle("dark-mode",theme==="dark");document.body.classList.toggle("dark-mode",theme==="dark");if(themeBtn){themeBtn.setAttribute("aria-pressed",theme==="dark"?"true":"false")}}setTheme(localStorage.getItem(themeKey)||"light");if(themeBtn){themeBtn.addEventListener("click",()=>{const next=document.body.classList.contains("dark-mode")?"light":"dark";localStorage.setItem(themeKey,next);setTheme(next)})}
const defaultGuests=[{name:"Nguyễn Minh Anh",message:"Chúc mừng Quỳnh nhé! Mong ngày tốt nghiệp của bạn thật nhiều niềm vui.",attend:"Sẽ đến",time:"Dữ liệu mẫu"},{name:"Trần Hoàng Nam",message:"Mình sẽ cố gắng sắp xếp thời gian để đến chúc mừng bạn.",attend:"Chưa chắc",time:"Dữ liệu mẫu"},{name:"Linh Chi",message:"Cuối cùng cũng đến ngày này rồi. Chúc mừng tân cử nhân Phạm Như Quỳnh!",attend:"Sẽ đến",time:"Dữ liệu mẫu"}];
const siteSettingsState={loaded:false,rows:{}};
const giftAuthState={checked:false,canAccess:false,permission:null};
function showGiftState(state){const guard=document.getElementById("giftGuard"),locked=document.getElementById("giftLocked"),open=document.getElementById("giftOpen");if(guard)guard.classList.toggle("hidden",state!=="guard");if(locked)locked.classList.toggle("hidden",state!=="locked");if(open)open.classList.toggle("hidden",state!=="open")}
function updateGiftGuardMessage(message,note){const text=document.getElementById("giftGuardText"),noteEl=document.getElementById("giftGuardNote");if(text)text.textContent=message;if(noteEl)noteEl.textContent=note||"Quyền truy cập được kiểm tra bằng Supabase Auth."}
async function readGiftPermission(){const client=getSupabaseClient();if(!client)return{canAccess:false,permission:null,hasSession:false};const{data:{session}}=await client.auth.getSession();if(!session)return{canAccess:false,permission:null,hasSession:false};const{data,error}=await client.from("admin_users").select("role,can_view_gift,can_preview_gift,email").limit(1).maybeSingle();if(error)throw error;return{canAccess:!!(data?.can_view_gift||data?.can_preview_gift),permission:data||null,hasSession:true}}
async function setupGiftGuard(){if(document.body.dataset.page!=="gift")return;showGiftState("guard");updateGiftGuardMessage("Đang kiểm tra quyền truy cập món quà...","Vui lòng chờ trong giây lát.");try{const result=await readGiftPermission();giftAuthState.checked=true;giftAuthState.canAccess=result.canAccess;giftAuthState.permission=result.permission;if(!result.hasSession){updateGiftGuardMessage("Trang này là một món quà riêng. Hãy đăng nhập bằng tài khoản đã được cấp quyền để mở.");showGiftState("guard");return}if(!result.canAccess){updateGiftGuardMessage("Tài khoản này chưa có quyền mở món quà riêng.","Hãy dùng tài khoản đã được cấp quyền can_view_gift hoặc can_preview_gift.");showGiftState("guard");return}showGiftState(isGiftUnlocked()?"open":"locked")}catch(error){console.error("Gift permission check failed:",error);updateGiftGuardMessage(`Chưa kiểm tra được quyền truy cập: ${error.message}`,"Bạn thử đăng nhập lại hoặc tải lại trang giúp mình nhé.");showGiftState("guard")}}
async function giftLogin(){const client=getSupabaseClient();if(!client){alert("Supabase chưa được cấu hình nên chưa thể đăng nhập.");return}const{error}=await client.auth.signInWithOAuth({provider:"google",options:{redirectTo:`${window.location.origin}${window.location.pathname}`}});if(error)alert(`Chưa đăng nhập được: ${error.message}`)}
async function giftLogout(){const client=getSupabaseClient();if(client)await client.auth.signOut();giftAuthState.checked=true;giftAuthState.canAccess=false;giftAuthState.permission=null;setupGiftGuard()}
setupGiftGuard();
let graduationDate=new Date(CONFIG.graduationDate).getTime();
const giftUnlockSettingsKey="pham-nhu-quynh-gift-unlock-settings";
function localDateTimeParts(value){if(!value)return{date:"",time:""};const date=new Date(value);if(Number.isNaN(date.getTime()))return{date:"",time:""};const pad=n=>String(n).padStart(2,"0");return{date:`${date.getFullYear()}-${pad(date.getMonth()+1)}-${pad(date.getDate())}`,time:`${pad(date.getHours())}:${pad(date.getMinutes())}`}}
function readGiftUnlockSettings(){const remote=siteSettingsState.rows.gift_settings?.value;if(remote){if(remote.unlock_at)return localDateTimeParts(remote.unlock_at);return{date:remote.date||"",time:remote.time||""}}try{const parsed=JSON.parse(localStorage.getItem(giftUnlockSettingsKey)||"{}");return{date:parsed.date||"",time:parsed.time||""}}catch{return{date:"",time:""}}}
function getGiftUnlockTime(){const settings=readGiftUnlockSettings();if(!settings.date||!settings.time)return Number.POSITIVE_INFINITY;const value=new Date(`${settings.date}T${settings.time}:00+07:00`).getTime();return Number.isNaN(value)?Number.POSITIVE_INFINITY:value}
let giftUnlockDate=getGiftUnlockTime();
function isGiftUnlocked(){return Number.isFinite(giftUnlockDate)&&Date.now()>=giftUnlockDate}
function getActiveCountdownDate(){return document.body.dataset.page==="gift"?giftUnlockDate:graduationDate}
function updateCountdown(){const now=Date.now();const activeCountdownDate=getActiveCountdownDate();const distance=Number.isFinite(activeCountdownDate)?activeCountdownDate-now:0;const safeDistance=Math.max(distance,0);const days=Math.floor(safeDistance/(1000*60*60*24));const hours=Math.floor((safeDistance/(1000*60*60))%24);const minutes=Math.floor((safeDistance/(1000*60))%60);const seconds=Math.floor((safeDistance/1000)%60);setText("days",days);setText("hours",hours);setText("minutes",minutes);setText("seconds",seconds);setText("adminDays",days);setText("adminHours",hours);setText("adminMinutes",minutes);setText("adminSeconds",seconds);setText("giftDays",days);setText("giftHours",hours);setText("giftMinutes",minutes);setText("giftSeconds",seconds);if(isGiftUnlocked()&&document.body.dataset.page==="gift"&&giftAuthState.canAccess){showGiftState("open")}}
function setText(id,value){const el=document.getElementById(id);if(el){el.textContent=String(value).padStart(2,"0")}}setInterval(updateCountdown,1000);updateCountdown();
const musicBtn=document.getElementById("musicBtn"),bgMusic=document.getElementById("bgMusic");if(musicBtn&&bgMusic){let isPlaying=false;musicBtn.addEventListener("click",async()=>{try{if(!isPlaying){await bgMusic.play();musicBtn.textContent="Ⅱ";musicBtn.classList.add("playing");isPlaying=true}else{bgMusic.pause();musicBtn.textContent="♫";musicBtn.classList.remove("playing");isPlaying=false}}catch(error){alert("Chưa có file nhạc hoặc trình duyệt đang chặn phát nhạc. Hãy đặt file assets/music.mp3 rồi thử lại.")}})}
const menuBtn=document.getElementById("menuBtn"),closeMenuBtn=document.getElementById("closeMenuBtn"),sideMenu=document.getElementById("sideMenu"),menuBackdrop=document.getElementById("menuBackdrop");function openMenu(){if(!sideMenu||!menuBackdrop)return;sideMenu.classList.add("open");menuBackdrop.classList.add("open");document.body.classList.add("menu-open")}function closeMenu(){if(!sideMenu||!menuBackdrop)return;sideMenu.classList.remove("open");menuBackdrop.classList.remove("open");document.body.classList.remove("menu-open")}if(menuBtn)menuBtn.addEventListener("click",openMenu);if(closeMenuBtn)closeMenuBtn.addEventListener("click",closeMenu);if(menuBackdrop)menuBackdrop.addEventListener("click",closeMenu);document.querySelectorAll("[data-menu-link]").forEach(link=>{link.addEventListener("click",closeMenu)});
function getGuests(){const raw=localStorage.getItem(CONFIG.storageKey);if(!raw)return defaultGuests;try{const parsed=JSON.parse(raw);if(Array.isArray(parsed))return parsed;return defaultGuests}catch{return defaultGuests}}function saveGuests(guests){localStorage.setItem(CONFIG.storageKey,JSON.stringify(guests))}
function getSupabaseClient(){return window.GRADUATION_SUPABASE?.isConfigured?window.GRADUATION_SUPABASE.client:null}
async function loadSiteSettings(){const client=getSupabaseClient();if(!client)return null;const{data,error}=await client.from("site_settings").select("key,value,is_public,owner_can_update,admin_can_update");if(error)throw error;siteSettingsState.rows=Object.fromEntries((data||[]).map(row=>[row.key,row]));siteSettingsState.loaded=true;return siteSettingsState.rows}
function applyProfileSettings(){const profile=siteSettingsState.rows.invitation_profile?.value;if(!profile)return;const fullName=profile.full_name||profile.toolbar_title||profile.display_name;const displayName=profile.display_name||fullName;if(profile.page_title)document.title=profile.page_title;const description=document.querySelector('meta[name="description"]');if(description&&profile.meta_description)description.setAttribute("content",profile.meta_description);document.querySelectorAll(".toolbar-title").forEach(el=>{if(profile.toolbar_title)el.textContent=profile.toolbar_title});document.querySelectorAll(".hero-name").forEach(el=>{if(fullName)el.textContent=fullName});document.querySelectorAll(".admin-dashboard-name,.admin-login-heading h1,.gift-script-name").forEach(el=>{if(displayName)el.textContent=displayName})}
function applyPageTextSettings(){const text=siteSettingsState.rows.page_text?.value;if(!text)return;const map={quote:text.quote,formThanks:text.form_thanks||text.formThanks,school:siteSettingsState.rows.event_details?.value?.school};Object.entries(map).forEach(([key,value])=>{if(!value)return;document.querySelectorAll(`[data-config-text="${key}"]`).forEach(el=>{el.textContent=value})})}
function normalizeEventSettings(value={}){return{...defaultInvitationSettings,day:String(value.day||defaultInvitationSettings.day).padStart(2,"0"),month:value.month||defaultInvitationSettings.month,year:String(value.year||defaultInvitationSettings.year),startTime:value.start_time||value.startTime||defaultInvitationSettings.startTime,endTime:value.end_time||value.endTime||defaultInvitationSettings.endTime,school:value.school||defaultInvitationSettings.school,hall:value.hall||defaultInvitationSettings.hall,address:value.address||defaultInvitationSettings.address}}
function eventSettingsToSiteValue(settings){const current=siteSettingsState.rows.event_details?.value||{};return{...current,day:String(settings.day).padStart(2,"0"),month:settings.month,year:String(settings.year),start_time:settings.startTime,end_time:settings.endTime,timezone:current.timezone||"Asia/Ho_Chi_Minh",school:settings.school||current.school||defaultInvitationSettings.school,hall:settings.hall,address:settings.address}}
async function initSiteSettings(){try{const rows=await loadSiteSettings();if(!rows)return;applyProfileSettings();applyPageTextSettings();if(rows.event_details?.value)applyInvitationSettings(normalizeEventSettings(rows.event_details.value));if(rows.gift_settings?.value){giftUnlockDate=getGiftUnlockTime();populateUpdateForm(readInvitationSettings());updateCountdown();if(document.body.dataset.page==="gift"&&giftAuthState.canAccess)showGiftState(isGiftUnlocked()?"open":"locked")}}catch(error){console.warn("Site settings fallback is active:",error)}}
async function submitGuestbookEntry(entry){const client=getSupabaseClient();if(!client){console.warn("Supabase is not configured; guestbook entry was saved to localStorage only.");const guests=getGuests();guests.unshift({name:entry.name,message:entry.message,attend:entry.attend,time:new Date().toLocaleString("vi-VN")});saveGuests(guests);return{mode:"local"}}const{error}=await client.from("guestbook_entries").insert({guest_name:entry.name,message:entry.message,attend_status:entry.attend,user_agent:navigator.userAgent||null,is_hidden:false});if(error)throw error;return{mode:"supabase"}}
function showGuestbookThanks(){if(formThanks){formThanks.style.display="block";setTimeout(()=>{formThanks.style.display="none"},4500)}}
const guestForm=document.getElementById("guestForm"),formThanks=document.getElementById("formThanks");if(guestForm){guestForm.addEventListener("submit",async event=>{event.preventDefault();const name=document.getElementById("guestName").value.trim();const message=document.getElementById("guestMessage").value.trim();const attend=document.getElementById("guestAttend").value;if(!name||!message){alert("Bạn hãy nhập tên và lời nhắn trước khi gửi nhé.");return}const submitButton=guestForm.querySelector('button[type="submit"]');const oldButtonText=submitButton?.textContent;if(submitButton){submitButton.disabled=true;submitButton.textContent="Đang gửi..."}try{await submitGuestbookEntry({name,message,attend});guestForm.reset();showGuestbookThanks()}catch(error){console.error("Guestbook submit failed:",error);alert(`Chưa gửi được lời nhắn: ${error?.message||"Bạn thử lại giúp mình nhé."}`)}finally{if(submitButton){submitButton.disabled=false;submitButton.textContent=oldButtonText||"Gửi lời nhắn & xác nhận"}}})}
const adminGuestbookState={filter:"all",newestFirst:true,hiddenOpen:false},adminAuthState={checked:false,isAuthorized:false,isChecking:false,alertShown:false,permission:null,guests:null};
function setAdminLoginLoading(isLoading){const btn=document.querySelector(".google-login-btn");if(btn){btn.disabled=!!isLoading;btn.setAttribute("aria-busy",isLoading?"true":"false")}}
function showAdminLogin(){teardownAdminGuestbookRealtime();const loginBox=document.getElementById("loginBox"),dashboardBox=document.getElementById("dashboardBox");if(loginBox&&dashboardBox){dashboardBox.classList.add("hidden");loginBox.classList.remove("hidden");document.body.classList.remove("admin-dashboard-open");updateAdminGuestbookFrameHeight()}}
function showAdminDashboard(){const loginBox=document.getElementById("loginBox"),dashboardBox=document.getElementById("dashboardBox");if(loginBox&&dashboardBox){loginBox.classList.add("hidden");dashboardBox.classList.remove("hidden");document.body.classList.add("admin-dashboard-open");setupAdminGuestbookRealtime();renderAdminDashboard();updateAdminGuestbookFrameHeight()}}
function updateAdminMenuUser(session){const el=document.getElementById("adminMenuUserName");if(!el)return;const user=session?.user;const meta=user?.user_metadata||{};el.textContent=meta.full_name||meta.name||user?.email||adminAuthState.permission?.email||"Admin"}
async function readAdminPermission(){const client=getSupabaseClient();if(!client)return{authorized:true,permission:null,mode:"local"};const{data:{session}}=await client.auth.getSession();if(!session)return{authorized:false,permission:null,mode:"supabase"};const{data,error}=await client.from("admin_users").select("role,can_read_guestbook,can_manage_guestbook,can_view_gift,can_preview_gift,email").limit(1).maybeSingle();if(error)throw error;return{authorized:!!data?.can_read_guestbook,permission:data||null,mode:"supabase"}}
async function adminLogin(){const client=getSupabaseClient();if(!client){showAdminDashboard();return}setAdminLoginLoading(true);const{data:{session}}=await client.auth.getSession();if(session){await setupAdminAuth();setAdminLoginLoading(false);return}const{error}=await client.auth.signInWithOAuth({provider:"google",options:{redirectTo:`${window.location.origin}${window.location.pathname}`}});if(error){setAdminLoginLoading(false);console.error("Admin login failed:",error);alert(`Chưa đăng nhập được: ${error.message}`)}}
async function adminLogout(){const client=getSupabaseClient();closeMenu();teardownAdminGuestbookRealtime();if(client){await client.auth.signOut()}adminAuthState.checked=true;adminAuthState.isAuthorized=false;adminAuthState.permission=null;adminAuthState.guests=null;updateAdminMenuUser(null);showAdminLogin()}
function updateAdminRoleControls(){const giftSettings=document.getElementById("giftUnlockSettings");if(giftSettings)giftSettings.classList.toggle("hidden",adminAuthState.permission?.role!=="admin")}
async function setupAdminAuth(options={}){if(document.body.dataset.page!=="admin"||adminAuthState.isChecking)return;const client=getSupabaseClient();if(!client){adminAuthState.checked=true;adminAuthState.isAuthorized=true;showAdminLogin();return}adminAuthState.isChecking=true;setAdminLoginLoading(true);try{const{data:{session}}=await client.auth.getSession();updateAdminMenuUser(session);const result=await readAdminPermission();adminAuthState.checked=true;adminAuthState.isAuthorized=result.authorized;adminAuthState.permission=result.permission;updateAdminMenuUser(session);updateAdminRoleControls();if(result.authorized){adminAuthState.alertShown=false;await initSiteSettings();showAdminDashboard()}else{showAdminLogin();if(session&&!options.silent&&!adminAuthState.alertShown){adminAuthState.alertShown=true;alert("Tài khoản này chưa có quyền đọc sổ lưu bút. Hãy thêm email vào bảng admin_users.")}}}catch(error){console.error("Admin permission check failed:",error);showAdminLogin();if(!options.silent)alert(`Chưa kiểm tra được quyền admin: ${error.message}`)}finally{adminAuthState.isChecking=false;setAdminLoginLoading(false)}}
function setupAdminAuthListener(){if(document.body.dataset.page!=="admin")return;const client=getSupabaseClient();if(!client)return;client.auth.onAuthStateChange((event,session)=>{if(event==="SIGNED_OUT"||!session){teardownAdminGuestbookRealtime();adminAuthState.checked=true;adminAuthState.isAuthorized=false;adminAuthState.permission=null;adminAuthState.guests=null;showAdminLogin();return}setTimeout(()=>setupAdminAuth({silent:true}),0)})}
async function loadAdminGuests(){const client=getSupabaseClient();if(!client||!adminAuthState.isAuthorized)return getGuests().map((guest,index)=>({...guest,id:guest.id||`local-${index}`,hidden:!!guest.hidden}));const{data,error}=await client.from("guestbook_entries").select("id,guest_name,message,attend_status,created_at,is_hidden").order("created_at",{ascending:false});if(error)throw error;return(data||[]).map(row=>({id:row.id,name:row.guest_name,message:row.message,attend:row.attend_status,time:row.created_at?new Date(row.created_at).toLocaleString("vi-VN"):"",hidden:!!row.is_hidden}))}
async function renderAdminDashboard(){let guests=adminAuthState.guests||getGuests();const guestList=document.getElementById("guestList");if(guestList)guestList.innerHTML=`<p class="empty-guest">Đang tải lời nhắn...</p>`;try{guests=await loadAdminGuests();adminAuthState.guests=guests}catch(error){console.error("Admin guestbook load failed:",error);if(guestList)guestList.innerHTML=`<p class="empty-guest">Chưa tải được dữ liệu Supabase: ${escapeHtml(error.message)}</p>`;updateAdminGuestbookFrameHeight();return}const total=guests.length;const yes=guests.filter(g=>g.attend==="Sẽ đến").length;const maybe=guests.filter(g=>g.attend==="Chưa chắc").length;const no=guests.filter(g=>g.attend==="Không đến được").length;setText("statTotal",total);setText("statYes",yes);setText("statMaybe",maybe);setText("statNo",no);document.querySelectorAll("[data-guest-filter]").forEach(btn=>btn.classList.toggle("active",btn.dataset.guestFilter===adminGuestbookState.filter));const sortBtn=document.getElementById("guestSortBtn");if(sortBtn)sortBtn.classList.toggle("oldest-first",!adminGuestbookState.newestFirst);if(!guestList)return;let visible=adminGuestbookState.filter==="all"?[...guests]:guests.filter(g=>g.attend===adminGuestbookState.filter);if(!adminGuestbookState.newestFirst)visible=[...visible].reverse();if(visible.length===0){guestList.innerHTML=`<p class="empty-guest">Chưa có lời nhắn phù hợp.</p>`;updateAdminGuestbookFrameHeight();return}guestList.innerHTML=visible.map(renderAdminGuestCard).join("");updateAdminGuestbookFrameHeight()}
function clearGuestbook(){if(confirm("Bạn muốn xóa toàn bộ dữ liệu sổ lưu bút demo trong trình duyệt này?")){localStorage.removeItem(CONFIG.storageKey);adminAuthState.guests=null;renderAdminDashboard()}}function escapeHtml(value){return String(value).replaceAll("&","&amp;").replaceAll("<","&lt;").replaceAll(">","&gt;").replaceAll('"',"&quot;").replaceAll("'","&#039;")}function guestAttendClass(value){if(value==="Sẽ đến")return"attend-yes";if(value==="Chưa chắc")return"attend-maybe";if(value==="Không đến được")return"attend-no";return"attend-unknown"}function canManageGuestbook(){return !getSupabaseClient()||!!adminAuthState.permission?.can_manage_guestbook}function renderAdminGuestCard(g){const hidden=!!g.hidden,canManage=canManageGuestbook()&&g.id;const action=canManage?`<button class="guest-visibility-btn" type="button" data-guest-id="${escapeHtml(g.id)}" data-hidden="${hidden?"true":"false"}" aria-label="${hidden?"Bỏ ẩn":"Ẩn"} lời nhắn của ${escapeHtml(g.name)}">${hidden?"Bỏ ẩn":"Ẩn"}</button>`:"";return`<article class="admin-guest-message ${guestAttendClass(g.attend)}${hidden?" is-hidden-message":""}"><div class="admin-guest-message-head"><strong>${escapeHtml(g.name)}</strong><span class="guest-card-actions"><span class="guest-status-pill">${escapeHtml(g.attend)}</span>${action}</span></div><p>${escapeHtml(g.message)}</p><time>${escapeHtml(g.time||"")}</time></article>`}

const invitationSettingsKey="pham-nhu-quynh-invitation-settings";
const defaultInvitationSettings={day:"02",month:"August",year:"2026",startTime:"10:00",endTime:"12:00",school:"Trường Đại học Kinh tế - Đại học Quốc gia Hà Nội",hall:"Hội trường MMH",address:"Số 57 Phạm Hùng, Nam Từ Liêm, Hà Nội"};
function readInvitationSettings(){if(siteSettingsState.rows.event_details?.value)return normalizeEventSettings(siteSettingsState.rows.event_details.value);try{return{...defaultInvitationSettings,...JSON.parse(localStorage.getItem(invitationSettingsKey)||"{}")}}catch{return{...defaultInvitationSettings}}}
function monthToNumber(month){const value=String(month||"").trim().toLowerCase();const map={january:"01",jan:"01","tháng 1":"01","thang 1":"01",february:"02",feb:"02","tháng 2":"02","thang 2":"02",march:"03",mar:"03","tháng 3":"03","thang 3":"03",april:"04",apr:"04","tháng 4":"04","thang 4":"04",may:"05","tháng 5":"05","thang 5":"05",june:"06",jun:"06","tháng 6":"06","thang 6":"06",july:"07",jul:"07","tháng 7":"07","thang 7":"07",august:"08",aug:"08","tháng 8":"08","thang 8":"08",september:"09",sep:"09","tháng 9":"09","thang 9":"09",october:"10",oct:"10","tháng 10":"10","thang 10":"10",november:"11",nov:"11","tháng 11":"11","thang 11":"11",december:"12",dec:"12","tháng 12":"12","thang 12":"12"};if(/^\d{1,2}$/.test(value))return value.padStart(2,"0");return map[value]||"08"}
function weekdayLabel(settings){const labels=["Chủ nhật","Thứ hai","Thứ ba","Thứ tư","Thứ năm","Thứ sáu","Thứ bảy"];const date=new Date(`${settings.year}-${monthToNumber(settings.month)}-${String(settings.day).padStart(2,"0")}T00:00:00+07:00`);return Number.isNaN(date.getTime())?"Chủ nhật":labels[date.getDay()]}
function applyInvitationSettings(settings=readInvitationSettings()){const timeText=`${settings.startTime} - ${settings.endTime}`;document.querySelectorAll('[data-invitation-setting="weekday"]').forEach(el=>{el.textContent=weekdayLabel(settings)});document.querySelectorAll('[data-invitation-setting="day"]').forEach(el=>{el.textContent=String(settings.day).padStart(2,"0")});document.querySelectorAll('[data-invitation-setting="month"]').forEach(el=>{el.textContent=settings.month});document.querySelectorAll('[data-invitation-setting="year"]').forEach(el=>{el.textContent=settings.year});document.querySelectorAll('[data-invitation-setting="time"]').forEach(el=>{el.textContent=timeText});document.querySelectorAll('[data-invitation-setting="hall"]').forEach(el=>{el.textContent=settings.hall});document.querySelectorAll('[data-invitation-setting="address"]').forEach(el=>{el.textContent=settings.address});document.querySelectorAll('[data-config-text="school"]').forEach(el=>{if(settings.school)el.textContent=settings.school});const heroDate=document.querySelector(".date-text");if(heroDate){heroDate.textContent=`${String(settings.day).padStart(2,"0")} . ${monthToNumber(settings.month)} . ${settings.year}`}const mapBtn=document.querySelector(".event-map-btn");if(mapBtn){mapBtn.href=`https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(settings.address)}`}graduationDate=new Date(`${settings.year}-${monthToNumber(settings.month)}-${String(settings.day).padStart(2,"0")}T${settings.startTime}:00+07:00`).getTime()}
