const updateMonthNames=["January","February","March","April","May","June","July","August","September","October","November","December"];
function canonicalMonthName(month){const number=Math.max(1,Math.min(12,parseInt(monthToNumber(month),10)||8));return updateMonthNames[number-1]}
function daysInUpdateMonth(year,month){const y=parseInt(year,10)||2026;const m=parseInt(monthToNumber(month),10)||8;return new Date(y,m,0).getDate()}
function fillSelectOptions(select,values,currentValue){if(!select)return;const current=String(currentValue||"");select.innerHTML=values.map(value=>`<option value="${escapeHtml(value)}"${String(value)===current?" selected":""}>${escapeHtml(value)}</option>`).join("")}
function populateUpdateDateSelects(settings=readInvitationSettings()){const yearEl=document.getElementById("settingYear"),monthEl=document.getElementById("settingMonth"),dayEl=document.getElementById("settingDay");const allowedYears=["2026","2027","2028"];const rawYear=String(settings.year||defaultInvitationSettings.year);const selectedYear=allowedYears.includes(rawYear)?rawYear:defaultInvitationSettings.year;fillSelectOptions(yearEl,allowedYears,selectedYear);const selectedMonth=canonicalMonthName(settings.month);fillSelectOptions(monthEl,updateMonthNames,selectedMonth);const maxDay=daysInUpdateMonth(selectedYear,selectedMonth);const selectedDay=String(Math.min(maxDay,Math.max(1,parseInt(settings.day,10)||1))).padStart(2,"0");fillSelectOptions(dayEl,Array.from({length:maxDay},(_,i)=>String(i+1).padStart(2,"0")),selectedDay)}
function populateUpdateForm(settings=readInvitationSettings()){const set=(id,value)=>{const el=document.getElementById(id);if(el)el.value=value};populateUpdateDateSelects(settings);set("settingStartTime",settings.startTime);set("settingEndTime",settings.endTime);set("settingHall",settings.hall);set("settingAddress",settings.address);const giftSettings=readGiftUnlockSettings();set("giftUnlockDateInput",giftSettings.date);set("giftUnlockTimeInput",giftSettings.time)}
function getUpdateFormSettings(){return{year:document.getElementById("settingYear")?.value||defaultInvitationSettings.year,month:document.getElementById("settingMonth")?.value||defaultInvitationSettings.month,day:(document.getElementById("settingDay")?.value||defaultInvitationSettings.day).padStart(2,"0"),startTime:document.getElementById("settingStartTime")?.value||defaultInvitationSettings.startTime,endTime:document.getElementById("settingEndTime")?.value||defaultInvitationSettings.endTime,hall:(document.getElementById("settingHall")?.value||defaultInvitationSettings.hall).trim(),address:(document.getElementById("settingAddress")?.value||defaultInvitationSettings.address).trim()}}
function getGiftUnlockFormSettings(){return{date:document.getElementById("giftUnlockDateInput")?.value||"",time:document.getElementById("giftUnlockTimeInput")?.value||""}}
async function saveInvitationSettings(settings){const client=getSupabaseClient();if(!client){localStorage.setItem(invitationSettingsKey,JSON.stringify(settings));return{mode:"local"}}const value=eventSettingsToSiteValue(settings);const{data,error}=await client.from("site_settings").update({value}).eq("key","event_details").select("key,value,is_public,owner_can_update,admin_can_update").single();if(error)throw error;siteSettingsState.rows.event_details=data;siteSettingsState.loaded=true;return{mode:"supabase"}}
