function showUpdateStatus(message,isError=false){const status=document.getElementById("updateStatus");if(!status)return;status.textContent=message;status.classList.toggle("error",!!isError);status.classList.add("show");clearTimeout(status._hideTimer);status._hideTimer=setTimeout(()=>{status.classList.remove("show","error");status.textContent=""},isError?5200:3200)}
