function setupAdminGuestbookControls(){document.querySelectorAll("[data-guest-filter]").forEach(btn=>{btn.addEventListener("click",()=>{adminGuestbookState.filter=btn.dataset.guestFilter||"all";renderAdminDashboard()})});const sortBtn=document.getElementById("guestSortBtn");if(sortBtn){sortBtn.addEventListener("click",()=>{adminGuestbookState.newestFirst=!adminGuestbookState.newestFirst;renderAdminDashboard()})}document.addEventListener("click",event=>{const toggle=event.target.closest("[data-hidden-guestbook-toggle]");if(toggle){adminGuestbookState.hiddenOpen=!adminGuestbookState.hiddenOpen;renderAdminDashboard();return}const btn=event.target.closest(".guest-visibility-btn");if(!btn)return;toggleGuestVisibility(btn.dataset.guestId,btn.dataset.hidden==="true",btn)})}
