/* GiftForQuynh gate: keep gift.html minimal while preserving Supabase permission checks */
function isGiftAdmin(permission){return permission?.role==="admin"&&!!(permission.can_preview_gift||permission.can_view_gift)}
function isGiftOwner(permission){return permission?.role==="owner"&&!!permission.can_view_gift}
function canOpenGiftForQuynh(permission){return isGiftAdmin(permission)||(isGiftOwner(permission)&&isGiftUnlocked())}
function setGiftGateText(status,message){const statusEl=document.getElementById("giftGateStatus"),messageEl=document.getElementById("giftGateMessage");if(statusEl)statusEl.textContent=status;if(messageEl)messageEl.textContent=message}
function renderGiftGate(permission,hasSession){const link=document.getElementById("giftForQuynhLink");const allowed=canOpenGiftForQuynh(permission);if(link)link.classList.toggle("hidden",!allowed);if(!hasSession){setGiftGateText("Chưa xác thực tài khoản","Trang này là món quà riêng. Hãy quay lại trang admin và đăng nhập bằng tài khoản đã được cấp quyền.");return}if(!permission?.can_view_gift&&!permission?.can_preview_gift){setGiftGateText("Chưa có quyền mở quà","Tài khoản hiện tại chưa được cấp quyền xem hoặc xem trước món quà.");return}if(isGiftAdmin(permission)){setGiftGateText("Chế độ quản trị","Chúc mừng tốt nghiệp Như Quỳnh");return}if(isGiftOwner(permission)&&isGiftUnlocked()){setGiftGateText("Đã đến thời điểm mở quà","Món quà của Quỳnh đã sẵn sàng.");return}setGiftGateText("Món quà đang được giữ lại","Chúc mừng tốt nghiệp Như Quỳnh")}
function renderGiftForQuynh(permission,hasSession){const status=document.getElementById("giftForQuynhStatus"),content=document.getElementById("giftForQuynhContent"),denied=document.getElementById("giftForQuynhDenied");const allowed=hasSession&&canOpenGiftForQuynh(permission);if(status)status.textContent=allowed?"Đã mở khóa":"Chưa thể mở món quà";if(content)content.classList.toggle("hidden",!allowed);if(denied)denied.classList.toggle("hidden",allowed)}
function showGiftState(){const page=document.body.dataset.page;if(page==="gift")renderGiftGate(giftAuthState.permission,!!giftAuthState.hasSession);if(page==="gift-for-quynh")renderGiftForQuynh(giftAuthState.permission,!!giftAuthState.hasSession)}
async function setupGiftGuard(){const page=document.body.dataset.page;if(page!=="gift"&&page!=="gift-for-quynh")return;if(page==="gift")setGiftGateText("Đang kiểm tra quyền truy cập","Mình đang kiểm tra tài khoản và thời điểm mở quà.");try{const result=await readGiftPermission();giftAuthState.checked=true;giftAuthState.hasSession=result.hasSession;giftAuthState.canAccess=result.canAccess;giftAuthState.permission=result.permission;if(!siteSettingsState.loaded){try{await loadSiteSettings()}catch(error){console.warn("Gift settings fallback is active:",error)}}giftUnlockDate=getGiftUnlockTime();showGiftState()}catch(error){console.error("Gift permission check failed:",error);giftAuthState.checked=true;giftAuthState.hasSession=false;giftAuthState.canAccess=false;giftAuthState.permission=null;if(page==="gift")setGiftGateText("Chưa kiểm tra được quyền truy cập",`Bạn thử tải lại trang giúp mình nhé. Chi tiết: ${error.message}`);if(page==="gift-for-quynh")renderGiftForQuynh(null,false)}}
setupGiftGuard();
